+		bool use_inference_params = false,
+		EGradientMode param_gradients_mode = EGradientMode::Overwrite
+	) override {
+		if (!dL_dinput || padded_output_width() == 0) {
+			return;
+		}
+
+		linear_kernel(empty_backward<T>, 0, stream,
+			input.n() * m_n_dims_to_encode,
+			m_n_dims_to_encode,
+			dL_dinput->view()
+		);
+	}
