+	uint32_t required_output_alignment() const override {
+		return 1;
+	}
+
+	MatrixLayout preferred_output_layout() const override {
+		return AoS;
+	}
+
+	json hyperparams() const override {
+		return {
+			{"otype", "Empty"},
+		};
+	}
+
+private:
+	uint32_t m_n_dims_to_encode;
+	uint32_t m_n_to_pad = 0;
+};
