+/** @file   composite.h
+ *  @author Sergei Solonets, Technical University of Munich
+ *  @brief  Allow using different optimizer on different parameters.
+ */
+
+#pragma once
+
+#include <tiny-cuda-nn/common.h>
+#include <tiny-cuda-nn/gpu_memory.h>
