+            // left
+            pos_grid_local[grad_dim] = pos_grid[grad_dim];
+            add_grid_gradient(pos_grid_local, grad, -weight);
+            // right
+            pos_grid_local[grad_dim] = pos_grid[grad_dim] + 1;
+            add_grid_gradient(pos_grid_local, grad, weight);
+        }
+    }
