+	const uint32_t num_elements,
+	const uint32_t num_grid_features,
+	// inputs
+	PitchedPtr<const float> dL_ddLdx,
+	const float* __restrict__ dy_dx,
+	const T* dL_dy_rm,
+	// ouputs
+	tcnn::PitchedPtr<T> dL_ddLdy
