-__device__ inline uint64_t morton3D_64bit(uint32_t x, uint32_t y, uint32_t z)  {
-	return ((expand_bits((uint64_t)x)) | (expand_bits((uint64_t)y) << 1) | (expand_bits((uint64_t)z) << 2));
