+
+template <typename T>
+TCNN_HOST_DEVICE void inline host_device_swap(T& a, T& b) {
+	T c(a); a=b; b=c;
+}
+
+template <typename T>
+TCNN_HOST_DEVICE T gcd(T a, T b) {
+	while (a != 0) {
+		b %= a;
+		host_device_swap(a, b);
+	}
+	return b;
+}
+
+template <typename T>
+TCNN_HOST_DEVICE T lcm(T a, T b) {
+	T tmp = gcd(a, b);
+	return tmp ? (a / tmp) * b : 0;
+}
